Code Example
library(hfportal)

uga &lt;- get_facilities(country = "UGA", version = "1.0")

library(dplyr)
uga |&gt;
  filter(!is.na(latitude)) |&gt;
  group_by(facility_type) |&gt;
  summarise(n = n(), pct_gps = mean(!is.na(longitude)) * 100) |&gt;
  arrange(desc(n))
